mapper.select:
select min(snapshot_date)
from stock_price_snapshots
where stock_id = #{stockId}

mapper.update:
update stocks
set
    ipo_date = #{ipoDate},
    updated_at = now()
where id = #{stockId}
  and (
      ipo_date is null
      or ipo_date <> #{ipoDate}
  )

mapper.select:
select current_price
from stock_price_snapshots
where stock_id = #{stockId}
  and snapshot_date <= #{targetDate}
  and snapshot_date >= #{oldestDate}
  and current_price is not null
  and current_price > 0
order by snapshot_date desc, id desc
limit 1
